// Import necessary packages
import 'dart:developer';

// Logging levels
enum LogLevel {
  debug,
  info,
  error,
}

// Function to log messages with different levels
void logMessage(String message, {LogLevel level = LogLevel.info}) {
  switch (level) {
    case LogLevel.debug:
      debugPrint(message);
      break;
    case LogLevel.info:
      print(message);
      break;
    case LogLevel.error:
      FlutterError.reportError(FlutterErrorDetails(exception: message));
      break;
  }
}

// Log HTTP requests/responses
void logHttpRequest(String url, {String? requestBody, String? response}) {
  logMessage('HTTP Request:', level: LogLevel.debug);
  logMessage('URL:', message: url, level: LogLevel.debug);
  logMessage('Request Body:', message: requestBody, level: LogLevel.debug);
  logMessage('Response:', message: response, level: LogLevel.debug);
}

// Log database operations
void logDatabaseOperation(String operation, {Map<String, dynamic>? data}) {
  logMessage('Database Operation:', level: LogLevel.debug);
  logMessage('Operation:', message: operation, level: LogLevel.debug);
  logMessage('Data:', message: data?.toString(), level: LogLevel.debug);
}

// Log authentication flows
void logAuthenticationFlow(String event, {Map<String, dynamic>? data}) {
  logMessage('Authentication Flow:', level: LogLevel.debug);
  logMessage('Event:', message: event, level: LogLevel.debug);
  logMessage('Data:', message: data?.toString(), level: LogLevel.debug);
}

// Log user interactions
void logUserInteraction(String event, {Map<String, dynamic>? data}) {
  logMessage('User Interaction:', level: LogLevel.debug);
  logMessage('Event:', message: event, level: LogLevel.debug);
  logMessage('Data:', message: data?.toString(), level: LogLevel.debug);
}